void Branch(int k)
{
    for (int v = 2; v <= n; v++) {
        if (visited[v] == FALSE) {
            x_k = v; visited[v] = TRUE;
            f = f + c(x_(k-1), x_k);

            if (k == n)  //Update record:
            {   if (f + c(x_n, x_1) < f*) f* = f + c(x_n, x_1);  }
            else {
                g = f + (n-k + 1)*cmin;  //calculate bound
                if (g < f*) Branch(k + 1);
            }
        }
    }

    f = f - c(x_(k-1), x_k);
    visited[v] = FALSE;
}
```

